"use client";

import { Moon, Sun } from "lucide-react";
import { useTheme } from "next-themes";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

export default function ThemeSelector() {
  const { setTheme, theme } = useTheme();

  const handleThemeChange = (newTheme: string) => {
    // Ensure only valid theme values are set
    const validThemes = ["light", "dark", "system"];
    if (validThemes.includes(newTheme)) {
      setTheme(newTheme);
    }
  };

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="outline" size="icon">
          <Sun className="h-[1.2rem] w-[1.2rem] scale-100 rotate-0 transition-all dark:scale-0 dark:-rotate-90" />
          <Moon className="absolute h-[1.2rem] w-[1.2rem] scale-0 rotate-90 transition-all dark:scale-100 dark:rotate-0" />
          <span className="sr-only">Toggle theme</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem onClick={() => handleThemeChange("light")}>
          Light
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleThemeChange("dark")}>
          Dark
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => handleThemeChange("system")}>
          System
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { getContributorProfile, getAllContributorUsernames } from "@/lib/db";
import { getConfig } from "@/lib/config";
import ActivityHeatmap from "@/components/Leaderboard/ActivityHeatmap";
import type { Metadata } from "next";
import type { ActivityItem } from "@/types/contributor";
import { Badge } from "@/components/ui/badge";

type Props = {
  params: Promise<{ username: string }>;
};

export async function generateStaticParams() {
  const usernames = await getAllContributorUsernames();
  return usernames.map((username: string) => ({
    username,
  }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { username } = await params;
  const profile = await getContributorProfile(username);
  const config = getConfig();

  if (!profile) {
    return {
      title: "User Not Found",
    };
  }

  return {
    title: `${profile.contributor.name || username} - ${config.meta.title}`,
    description: `Contributor profile for ${username} on ${config.org.name} Leaderboard.`,
  };
}

export default async function UserProfilePage({ params }: Props) {
  const { username } = await params;
  const profile = await getContributorProfile(username);

  if (!profile) {
    notFound();
  }

  const { contributor, activities, dailyActivity, totalPoints, stats } = profile;

  return (
    <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
      <div className="mb-8">
        <Link href="/people" className="flex items-center text-sm text-muted-foreground hover:text-primary transition-colors">
          <span className="mr-2">←</span> Back to People
        </Link>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        
        {/* SIDEBAR: Profile & Stats */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-card border rounded-xl p-6 shadow-sm">
            <div className="flex flex-col items-center text-center space-y-4">
              <div className="relative">
                <Image
                  src={contributor.avatar_url || '/default-avatar.png'}
                  alt={username}
                  width={140}
                  height={140}
                  className="rounded-2xl border-4 border-background shadow-lg"
                />
                {stats && stats.currentStreak > 0 && (
                  <div className="absolute -bottom-2 -right-2 bg-orange-500 text-white p-2 rounded-lg shadow-md animate-pulse-slow">
                    🔥 {stats.currentStreak}
                  </div>
                )}
              </div>
              
              <div>
                <h1 className="text-2xl font-bold tracking-tight">{contributor.name || username}</h1>
                <a 
                  href={`https://github.com/${username}`} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="text-muted-foreground hover:text-primary transition-colors text-sm"
                >
                  @{username}
                </a>
              </div>

              {contributor.role && (
                <div className="bg-secondary text-secondary-foreground text-[10px] uppercase font-bold tracking-widest px-3 py-1 rounded-full">
                  {contributor.role}
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4 mt-8 pt-8 border-t">
              <div className="text-center">
                <div className="text-xl font-bold">{totalPoints}</div>
                <div className="text-[10px] uppercase text-muted-foreground tracking-widest">Points</div>
              </div>
              <div className="text-center border-l">
                <div className="text-xl font-bold">{activities.length}</div>
                <div className="text-[10px] uppercase text-muted-foreground tracking-widest">Activities</div>
              </div>
            </div>
            
            {stats && (
               <div className="mt-4 p-3 bg-secondary/30 rounded-lg text-center">
                  <div className="text-sm font-medium text-blue-600 flex items-center justify-center gap-1">
                    <span className="text-lg">🏆</span> Best Streak: {stats.longestStreak} days
                  </div>
               </div>
            )}
          </div>

          {/* Activity Distribution Breakdown */}
          {stats?.distribution && (
            <div className="bg-card border rounded-xl p-6 shadow-sm">
              <h3 className="text-sm font-bold uppercase tracking-wider text-muted-foreground mb-4">Activity Distribution</h3>
              <div className="space-y-4">
                <DistributionBar label="Pull Requests" count={stats.distribution.prs} total={activities.length} color="bg-green-500" />
                <DistributionBar label="Issues" count={stats.distribution.issues} total={activities.length} color="bg-blue-500" />
                <DistributionBar label="Reviews & Others" count={stats.distribution.others} total={activities.length} color="bg-purple-500" />
              </div>
            </div>
          )}
          
          {/* Project Focus */}
          {stats?.top_repos && stats.top_repos.length > 0 && (
            <div className="bg-card border rounded-xl p-6 shadow-sm">
                <h3 className="text-sm font-bold uppercase tracking-wider text-muted-foreground mb-4">Project Focus</h3>
                <div className="flex flex-wrap gap-2">
                  {stats.top_repos.map((repo: string) => (
                    <Badge key={repo} variant="secondary" className="text-[10px] font-bold uppercase tracking-tight py-1 px-3">
                      {repo}
                    </Badge>
                  ))}
                </div>
            </div>
          )}
        </div>

        {/* MAIN CONTENT: Heatmap & Timeline */}
        <div className="lg:col-span-8 space-y-8">
          
          {/* Heatmap Section */}
          <div className="bg-card border rounded-xl p-6 shadow-sm">
            <div className="flex items-center justify-between mb-6">
               <h3 className="font-bold text-lg">Contribution History</h3>
               <div className="text-xs text-muted-foreground">in the last year</div>
            </div>
            <ActivityHeatmap dailyActivity={dailyActivity || []} username={username} />
          </div>

          {/* Activity Timeline */}
          <div className="space-y-6">
            <h3 className="font-bold text-xl px-2">Recent Timeline</h3>
            <div className="space-y-4">
              {activities.map((act: { slug?: string; type?: string; link?: string | null; title?: string | null; occured_at: Date; points?: number | null }, i: number) => (
                <TimelineItem key={`${act.slug || act.type || 'activity'}-${i}`} activity={act as unknown as React.ComponentProps<typeof TimelineItem>['activity']} />
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function DistributionBar({ label, count, total, color }: { label: string, count: number, total: number, color: string }) {
  const percentage = total > 0 ? (count / total) * 100 : 0;
  return (
    <div className="space-y-1">
      <div className="flex justify-between text-xs font-medium">
        <span>{label}</span>
        <span className="text-muted-foreground">{count} ({Math.round(percentage)}%)</span>
      </div>
      <div className="h-2 w-full bg-secondary rounded-full overflow-hidden">
        <div className={`h-full ${color} rounded-full transition-all duration-500`} style={{ width: `${percentage}%` }}></div>
      </div>
    </div>
  )
}

function TimelineItem({ activity }: { activity: { slug?: string; type?: string; link?: string | null; title?: string | null; occured_at: string | Date; points?: number | null } }) {
  return (
    <div className="bg-white border rounded-xl p-5 shadow-sm hover:border-primary/50 transition-all group">
      <div className="flex items-start justify-between">
        <div className="space-y-1">
          <div className="font-semibold group-hover:text-primary transition-colors underline-offset-4 decoration-primary/30">
            {activity.link ? (
              <a href={activity.link} target="_blank" rel="noopener noreferrer">{activity.title || "Untitled Activity"}</a>
            ) : (
              activity.title || "Untitled Activity"
            )}
          </div>
          <div className="flex items-center text-xs text-muted-foreground gap-2">
            <span className="px-1.5 py-0.5 rounded bg-secondary uppercase font-bold text-[8px] tracking-widest">
              {(activity.slug ? activity.slug.split('-')[1]?.replace('_', ' ') : activity.type) || "ACTIVITY"}
            </span>
            <span>•</span>
            <span>{new Date(activity.occured_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</span>
          </div>
        </div>
        {activity.points && activity.points > 0 ? (
          <div className="text-sm font-bold text-green-600 bg-green-50 px-2 py-1 rounded-md">
            +{activity.points} pts
          </div>
        ) : null}
      </div>
    </div>
  )
}

import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";

export const runtime = "nodejs";

interface ReviewMetrics {
  totalReviews: number;
  reviewsLast7Days: number;
  reviewsLast30Days: number;
  averageReviewTimeHours: number;
  topReviewers: Array<{
    username: string;
    reviewCount: number;
    avatarUrl: string;
  }>;
  reviewVelocity: {
    daily: number;
    weekly: number;
    monthly: number;
  };
  dailyReviewData: Array<{
    date: string;
    reviews: number;
    avgTimeHours: number;
  }>;
  reviewStateDistribution: {
    approved: number;
    changesRequested: number;
    commented: number;
    pending: number;
  };
  prsNeedingReview: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    ageHours: number;
    isDraft: boolean;
  }>;
  prsReadyToMerge: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    approvals: number;
    ageHours: number;
  }>;
}

interface IssueMetrics {
  totalIssues: number;
  openIssues: number;
  closedIssues: number;
  pendingTriage: number;
  recentlyTriaged: number;
  triageVelocity: {
    daily: number;
    weekly: number;
  };
  ageDistribution: {
    lessThan24h: number;
    oneToSevenDays: number;
    sevenToThirtyDays: number;
    moreThanThirtyDays: number;
  };
  dailyTriageData: Array<{
    date: string;
    triaged: number;
    pending: number;
    total: number;
  }>;
  issuesPendingTriage: Array<{
    number: number;
    title: string;
    author: string;
    authorAvatar: string;
    createdAt: string;
    url: string;
    repository: string;
    ageHours: number;
    labels: string[];
  }>;
}

interface AnalyticsData {
  organization: string;
  lastUpdated: string;
  reviewMetrics: ReviewMetrics;
  issueMetrics: IssueMetrics;
  repositories: number;
}

export async function GET(request: Request) {
  try {
    // Read analytics data from the generated JSON file
    const analyticsPath = path.join(process.cwd(), 'public', 'analytics', 'analytics.json');
    
    if (!fs.existsSync(analyticsPath)) {
      return NextResponse.json({ 
        error: "Analytics data not found. Please run 'npm run generate:analytics' to generate the data." 
      }, { status: 404 });
    }
    
    const analyticsData: AnalyticsData = JSON.parse(fs.readFileSync(analyticsPath, 'utf-8'));

    // Always return all analytics data
    return NextResponse.json(analyticsData, {
      headers: {
        'Cache-Control': 'public, s-maxage=300, stale-while-revalidate=600',
      },
    });

  } catch (error) {
    console.error("Error reading analytics data:", error);
    return NextResponse.json(
      { 
        error: "Failed to read analytics data", 
        details: error instanceof Error ? error.message : "Unknown error",
        suggestion: "Try running 'npm run generate:analytics' to generate fresh data."
      },
      { status: 500 }
    );
  }
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { ExternalLink, Clock, CheckCircle, GitMerge } from "lucide-react";
import Link from "next/link";

interface PullRequest {
  number: number;
  title: string;
  author: string;
  authorAvatar: string;
  createdAt: string;
  url: string;
  repository: string;
  approvals: number;
  ageHours: number;
}

interface AnalyticsData {
  reviewMetrics: {
    prsReadyToMerge: PullRequest[];
  };
}

export function ReadyToMergeList() {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch('/api/analytics');
        if (!response.ok) {
          throw new Error('Failed to fetch PRs ready to merge');
        }
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setIsLoading(false);
      }
    }

    fetchData();
  }, []);

  const formatAge = (hours: number) => {
    if (hours < 24) {
      return `${Math.round(hours)}h ago`;
    } else if (hours < 24 * 7) {
      return `${Math.round(hours / 24)}d ago`;
    } else {
      return `${Math.round(hours / 24 / 7)}w ago`;
    }
  };

  if (isLoading) {
    return (
      <Card>
        <CardHeader>
          <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-1/2 animate-pulse"></div>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {[1, 2, 3, 4, 5].map((i) => (
              <div key={i} className="flex items-center space-x-3 animate-pulse">
                <div className="h-10 w-10 bg-gray-200 dark:bg-gray-700 rounded-full"></div>
                <div className="flex-1 space-y-2">
                  <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
                  <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-1/2"></div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="text-center text-red-600 dark:text-red-400">
            Error loading PRs ready to merge: {error}
          </div>
        </CardContent>
      </Card>
    );
  }

  const prsReadyToMerge = data?.reviewMetrics?.prsReadyToMerge || [];

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <GitMerge className="h-5 w-5" />
          PRs Ready to Merge ({prsReadyToMerge.length})
        </CardTitle>
        <CardDescription>
          Pull requests that have been approved and are ready for merging
        </CardDescription>
      </CardHeader>
      <CardContent>
        {prsReadyToMerge.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            No PRs ready to merge at the moment
          </div>
        ) : (
          <div className="max-h-96 overflow-y-auto">
            <div className="space-y-4">
              {prsReadyToMerge.map((pr) => (
              <div key={`${pr.repository}-${pr.number}`} className="flex items-start space-x-3 p-3 rounded-lg border bg-card hover:bg-accent/50 transition-colors">
                <Avatar className="h-8 w-8 mt-1">
                  <AvatarImage src={pr.authorAvatar} alt={pr.author || 'Unknown'} />
                  <AvatarFallback>{(pr.author || '?').slice(0, 2).toUpperCase()}</AvatarFallback>
                </Avatar>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <Badge variant="outline" className="text-xs">
                      {pr.repository}
                    </Badge>
                    <Badge variant="secondary" className="text-xs">
                      #{pr.number}
                    </Badge>
                  </div>
                  <Link 
                    href={pr.url} 
                    target="_blank"
                    rel="noopener noreferrer"
                    className="font-medium text-sm hover:underline flex items-center gap-1"
                  >
                    {pr.title}
                    <ExternalLink className="h-3 w-3" />
                  </Link>
                  <div className="flex items-center gap-4 mt-2 text-xs text-muted-foreground">
                    <span>by {pr.author}</span>
                    <span className="flex items-center gap-1">
                      <Clock className="h-3 w-3" />
                      {formatAge(pr.ageHours)}
                    </span>
                  </div>
                </div>
              </div>
            ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { GitPullRequest, Clock, TrendingUp, Users, Divide } from "lucide-react";

interface ReviewMetrics {
  totalReviews: number;
  reviewsLast7Days: number;
  reviewsLast30Days: number;
  averageReviewTimeHours: number;
  reviewVelocity: {
    daily: number;
    weekly: number;
    monthly: number;
  };
}

interface AnalyticsData {
  reviewMetrics: ReviewMetrics;
  lastUpdated: string;
}

export function ReviewMetricsCard() {
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch('/api/analytics');
        if (!response.ok) {
          throw new Error('Failed to fetch review metrics');
        }
        const result = await response.json();
        setData(result);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'An error occurred');
      } finally {
        setIsLoading(false);
      }
    }

    fetchData();
  }, []);

  if (isLoading) {
    return (
      <>
        {[1, 2, 3, 4].map((i) => (
          <Card key={i} className="animate-pulse w-full min-h-30">
            <CardHeader className="pb-2">
              <div className="h-4 bg-gray-200 dark:bg-gray-700 rounded w-3/4"></div>
            </CardHeader>
            <CardContent>
              <div className="h-8 bg-gray-200 dark:bg-gray-700 rounded w-1/2 mb-2"></div>
              <div className="h-3 bg-gray-200 dark:bg-gray-700 rounded w-full"></div>
            </CardContent>
          </Card>
        ))}
      </>
    );
  }

  if (error) {
    return (
      <Card className="col-span-full">
        <CardContent className="pt-6">
          <div className="text-center text-red-600 dark:text-red-400">
            Error loading review metrics: {error}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (!data) return null;

  const metrics = data.reviewMetrics;
  const changePercent = metrics.reviewsLast30Days > 0
    ? Math.round((metrics.reviewsLast7Days * 4 - metrics.reviewsLast30Days) / metrics.reviewsLast30Days * 100)
    : 0;

  return (
    <>
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Total Reviews</CardTitle>
          <GitPullRequest className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{metrics.totalReviews}</div>
          <p className="text-xs text-muted-foreground">
            {metrics.reviewsLast7Days} this week
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Avg Review Time</CardTitle>
          <Clock className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">
            {metrics.averageReviewTimeHours < 24
              ? `${metrics.averageReviewTimeHours}h`
              : `${Math.round(metrics.averageReviewTimeHours / 24)}d`
            }
          </div>
          <p className="text-xs text-muted-foreground">
            Time to first review
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Review Velocity</CardTitle>
          <TrendingUp className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{Math.round(metrics.reviewVelocity.daily * 10) / 10}</div>
          <p className="text-xs text-muted-foreground">
            Reviews per day
          </p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Weekly Trend</CardTitle>
          <Users className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{metrics.reviewsLast7Days}</div>
          <div className="flex items-center text-xs text-muted-foreground">
            {changePercent !== 0 && (
              <Badge
                variant={changePercent > 0 ? "default" : "secondary"}
                className={`mr-1 ${changePercent > 0 ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200' : 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200'}`}
              >
                {changePercent > 0 ? '+' : ''}{changePercent}%
              </Badge>
            )}
            vs last 30 days (projected)
          </div>
        </CardContent>
      </Card>
    </>
  );
}

"use client";

import { Card, CardContent } from "@/components/ui/card";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Trophy, GitMerge, GitPullRequest, AlertCircle, Eye, Tag, UserPlus, CheckCircle } from "lucide-react";
import { cn } from "@/lib/utils";
import ActivityTrendChart from "./ActivityTrendChart";
import "./LeaderboardCard.css";

const activityStyles: Record<string, {
  icon: React.ComponentType<{ className?: string }>;
  bgColor: string;
  textColor: string;
  borderColor: string;
}> = {
  "PR merged": {
    icon: GitMerge,
    bgColor: "bg-purple-500/10 dark:bg-purple-500/15",
    textColor: "text-purple-700 dark:text-purple-400",
    borderColor: "border-l-purple-500"
  },
  "PR opened": {
    icon: GitPullRequest,
    bgColor: "bg-blue-500/10 dark:bg-blue-500/15",
    textColor: "text-blue-700 dark:text-blue-400",
    borderColor: "border-l-blue-500"
  },
  "Issue opened": {
    icon: AlertCircle,
    bgColor: "bg-orange-500/10 dark:bg-orange-500/15",
    textColor: "text-orange-700 dark:text-orange-400",
    borderColor: "border-l-orange-500"
  },
  "Review submitted": {
    icon: Eye,
    bgColor: "bg-teal-500/10 dark:bg-teal-500/15",
    textColor: "text-teal-700 dark:text-teal-400",
