type ActivityUIConfig = {
  icon: React.ReactNode;
  gradient: string;
  borderColor: string;
  bgColor: string;
  iconBg: string;
  textColor: string;
  accentColor: string;
};


type ActivityKey =
  | "PR merged"
  | "PR opened"
  | "Issue opened"
  | "commit"
  | "star";

interface ContributorEntry {
  username: string;
  name: string | null;
  avatar_url: string;
  role: string;
  total_points: number;
  activity_breakdown: Record<string, { count: number; points: number }>;
  daily_activity: Array<{ date: string; count: number; points: number }>;
  current_streak?: number;
  longest_streak?: number;
  distribution?: {
